<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    [</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">System.Net.Sockets.AddressFamily</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]::InterNetwork</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span></span>
