<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$s.Connect(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;127.0.0.1&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">,</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 6064</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span>
